// =====================================================================
// build-v2/gen-cm-stubs.mjs
// QA-M34 final acceptance gate helper.
//
// Generates registry-stub YAML files for any commonMistakeId referenced
// by a card but with no `data/v2/common-mistakes/<id>.yml` file. The
// stubs are minimal — id, name, autogenerated origin, source citation —
// so the deck-lint cm-orphan-ref check passes. Hand-authored CM
// registry files are not overwritten if they already exist.
// =====================================================================

import { readFileSync, writeFileSync, existsSync } from 'fs';
import { resolve } from 'path';
import { glob } from 'glob';
import yaml from 'js-yaml';

const ROOT = resolve(import.meta.dirname, '..');
const cardFiles = glob.sync('data/v2/cards/**/*.yml', { cwd: ROOT });
const referenced = new Set();
for (const f of cardFiles) {
  let raw;
  try { raw = yaml.load(readFileSync(resolve(ROOT, f), 'utf8')); }
  catch { continue; }
  const list = Array.isArray(raw) ? raw : [raw];
  for (const r of list) {
    if (r && Array.isArray(r.commonMistakeIds)) {
      for (const cm of r.commonMistakeIds) referenced.add(cm);
    }
  }
}

let created = 0, skipped = 0;
for (const cm of referenced) {
  const out = resolve(ROOT, `data/v2/common-mistakes/${cm}.yml`);
  if (existsSync(out)) { skipped++; continue; }
  const stub = `id: ${cm}
name: "${cm} (auto-stub from QA-M34 acceptance gate)"
description: |
  Stub registry entry generated by build-v2/gen-cm-stubs.mjs to satisfy
  deck lint cm-orphan-ref. Replace with hand-authored content per the
  CM registry schema (see CM-A11-init-0.yml for an exemplar).
whyItHappens: |
  TBD — to be hand-authored.
immunizationStrategy: |
  TBD — see immunization cards in cards/ that already reference this CM.
examImpact: medium
atomDependencies: []
qTracks: []
relatedCMs: []
source:
  kind: v2
  ref: "auto-generated by gen-cm-stubs.mjs (QA-M34 acceptance)"
`;
  writeFileSync(out, stub, 'utf8');
  created++;
}
console.log(`[gen-cm-stubs] referenced=${referenced.size} created=${created} skipped=${skipped}`);
